def enum_block(name):
    pattern = rf"#\[derive\(Copy, Clone\)\]\npub enum {name} \{{.*?\n\}}\n\nimpl_iden!\({name} \{{.*?\n\}}\);\n"
    match = re.search(pattern, text, re.S)
    if not match:
        raise SystemExit(f'missing enum {name}')
    return match.group(0)

def const_block(name):
    pattern = rf"const {name}: &\[&str\] = &\[.*?\n\];\n"
    match = re.search(pattern, text, re.S)
    if not match:
        raise SystemExit(f'missing const {name}')
    return match.group(0)

prefix = 'use super::*;\n\n'

def write(name, pieces, specs):
